INSERT INTO public.localized_farmers (id, image_url, country_emoji) VALUES (4, 'https://lylnnqojnytndybhuicr.supabase.co/storage/v1/object/public/Farmers/farmer_oscar_francisca_chacon_1775463574148.png', 'https://lylnnqojnytndybhuicr.supabase.co/storage/v1/object/public/Flags/brazil_flag_glass_1775678129706.png');
INSERT INTO public.localized_farmer_translations (farmer_id, language_code, name, region, description, story, country) VALUES (4, 'en', 'Oscar & Francisca Chacón', 'Центральна Долина (Central Valley), муніципалітет Сабанілья-де-Алахуела (Sabanilla de Alajuela)', 'Оскар Чакон та його дружина Франциска — фермери у третьому поколінні, які перевернули кавову індустрію Коста-Рики. На початку 2000-х років країна славилася виключно ідеальною, чистою ''митою'' кавою. Проте в 2008 році стався потужний землетрус в регіоні Сінчона. Він зруйнував водопроводи та енергосистему саме в той момент, коли на фермі Las Lajas був пік збору врожаю. Родина Чакон фізично не могла змити м''якоть із зерен. Замість того, щоб викинути врожай, Оскар вирішив ризикнути: він розклав ягоди сушитися на сонці цілком, у м''якоті (сухий, натуральний метод), як це роблять в Ефіопії. Це вважалося ''божевіллям'' і некондицією для Коста-Рики. Проте, коли каву обсмажили, вона виявилася неймовірно солодкою, з густим ягідним профілем. Цей ''щасливий випадок'' зробив їх піонерами спешелті-натуралок у Центральній Америці. Вони одними з перших у регіоні побудували власний мікро-млин (Micromill), що дозволило їм самостійно контролювати обробку і не здавати ягоди на великі кооперативи. Крім того, Las Lajas — це одна з небагатьох ферм у Коста-Риці, що має сертифікат повної органіки. Вони використовують компост із власної кавової м''якоті, вермікультуру (розведення дощових черв''яків для добрива) і зберігають тіньові дерева для захисту ґрунту від ерозії.', 'Органічне землеробство, Екстремальні натуралки (Black Diamond, Perla Negra), Градація Хані обробки', 'Costa Rica');
INSERT INTO public.localized_farmer_translations (farmer_id, language_code, name, region, description, story, country) VALUES (4, 'uk', 'Оскар та Франциска Чакон', 'Центральна Долина (Central Valley), муніципалітет Сабанілья-де-Алахуела (Sabanilla de Alajuela)', 'Оскар Чакон та його дружина Франциска — фермери у третьому поколінні, які перевернули кавову індустрію Коста-Рики. На початку 2000-х років країна славилася виключно ідеальною, чистою ''митою'' кавою. Проте в 2008 році стався потужний землетрус в регіоні Сінчона. Він зруйнував водопроводи та енергосистему саме в той момент, коли на фермі Las Lajas був пік збору врожаю. Родина Чакон фізично не могла змити м''якоть із зерен. Замість того, щоб викинути врожай, Оскар вирішив ризикнути: він розклав ягоди сушитися на сонці цілком, у м''якоті (сухий, натуральний метод), як це роблять в Ефіопії. Це вважалося ''божевіллям'' і некондицією для Коста-Рики. Проте, коли каву обсмажили, вона виявилася неймовірно солодкою, з густим ягідним профілем. Цей ''щасливий випадок'' зробив їх піонерами спешелті-натуралок у Центральній Америці. Вони одними з перших у регіоні побудували власний мікро-млин (Micromill), що дозволило їм самостійно контролювати обробку і не здавати ягоди на великі кооперативи. Крім того, Las Lajas — це одна з небагатьох ферм у Коста-Риці, що має сертифікат повної органіки. Вони використовують компост із власної кавової м''якоті, вермікультуру (розведення дощових черв''яків для добрива) і зберігають тіньові дерева для захисту ґрунту від ерозії.', 'Органічне землеробство, Екстремальні натуралки (Black Diamond, Perla Negra), Градація Хані обробки', 'Коста-Рика');
INSERT INTO public.localized_farmers (id, image_url, country_emoji) VALUES (5, 'https://lylnnqojnytndybhuicr.supabase.co/storage/v1/object/public/Farmers/farmer_carlos_felipe_arcila_1775463591773.png', 'https://lylnnqojnytndybhuicr.supabase.co/storage/v1/object/public/Flags/colombia_flag_glass_1775678097214.png');
INSERT INTO public.localized_farmer_translations (farmer_id, language_code, name, region, description, story, country) VALUES (5, 'en', 'Carlos & Felipe Arcila', 'Департамент Кіндіо (Quindio), муніципалітет Піхао (Pijao)', 'Брати Карлос та Феліпе Арсіла — це колумбійські революціонери, які заснували експортну компанію Cofinet і змінили правила гри у ''ко-ферментації''. Їхня родина вирощувала каву 80 років, але брати, отримавши освіту інженерів, вирішили перетворити свою ферму Jardines del Eden (Райські сади) на випробувальний полігон. Вони спеціалізуються на інфузіях — процесі додавання сторонніх натуральних інгредієнтів під час бродіння кави. Їхній підхід викликає суперечки в індустрії (деякі пуристи вважають, що кава має смакувати лише кавою), але їхні лоти розкуповуються за секунди. Брати зрозуміли, що під час анаеробної ферментації дріжджі потребують цукру для життя. Замість того, щоб чекати, поки дріжджі з''їдять кавову м''якоть, Карлос і Феліпе почали додавати в танки свіже пюре полуниці, персика, соки маракуї, а також специфічні винні дріжджі. Дріжджі поїдають фруктовий цукор і переносять ароматичні молекули фруктів глибоко в пористу структуру кавового зерна. Це не штучний ароматизатор, а зміна самої хімії зерна на клітинному рівні.', 'Фруктова ко-ферментація (Інфузії), Крижана ферментація (Ice Fermentation), Анаеробна обробка', 'Colombia');
INSERT INTO public.localized_farmer_translations (farmer_id, language_code, name, region, description, story, country) VALUES (5, 'uk', 'Карлос та Феліпе Арсіла', 'Департамент Кіндіо (Quindio), муніципалітет Піхао (Pijao)', 'Брати Карлос та Феліпе Арсіла — це колумбійські революціонери, які заснували експортну компанію Cofinet і змінили правила гри у ''ко-ферментації''. Їхня родина вирощувала каву 80 років, але брати, отримавши освіту інженерів, вирішили перетворити свою ферму Jardines del Eden (Райські сади) на випробувальний полігон. Вони спеціалізуються на інфузіях — процесі додавання сторонніх натуральних інгредієнтів під час бродіння кави. Їхній підхід викликає суперечки в індустрії (деякі пуристи вважають, що кава має смакувати лише кавою), але їхні лоти розкуповуються за секунди. Брати зрозуміли, що під час анаеробної ферментації дріжджі потребують цукру для життя. Замість того, щоб чекати, поки дріжджі з''їдять кавову м''якоть, Карлос і Феліпе почали додавати в танки свіже пюре полуниці, персика, соки маракуї, а також специфічні винні дріжджі. Дріжджі поїдають фруктовий цукор і переносять ароматичні молекули фруктів глибоко в пористу структуру кавового зерна. Це не штучний ароматизатор, а зміна самої хімії зерна на клітинному рівні.', 'Фруктова ко-ферментація (Інфузії), Крижана ферментація (Ice Fermentation), Анаеробна обробка', 'Колумбія');
INSERT INTO public.localized_farmers (id, image_url, country_emoji) VALUES (6, 'https://lylnnqojnytndybhuicr.supabase.co/storage/v1/object/public/Farmers/farmer_adam_rachel_overton_1775463606712.png', 'https://lylnnqojnytndybhuicr.supabase.co/storage/v1/object/public/Flags/coffee_country_flags_1775678067772.png');
INSERT INTO public.localized_farmer_translations (farmer_id, language_code, name, region, description, story, country) VALUES (6, 'en', 'Adam Overton & Rachel Samuel', 'Бенчі-Маджі (Bench Maji), округ Менгеші (Mengeshi)', 'Історія Gesha Village — це справжній пригодницький роман у світі кави. Адам (американець, режисер-документаліст) та Рейчел (ефіопка, фотограф) приїхали до Ефіопії знімати кіно про каву, але закохалися в країну і вирішили створити власну ферму. Їхня мета була амбітною: повернути славу сорту Гейша на його історичну батьківщину. Сорт Гейша (Gesha) став світовим феноменом у Панамі, але його коріння походить з джунглів Ефіопії. У 2011 році, заручившись підтримкою ботаніків, Адам і Рейчел вирушили в експедицію до диких, незвіданих лісів Горі Геша. Вони зібрали там насіння дикорослих кавових дерев і посадили їх на своїй новій фермі площею 471 гектар (з яких 320 га засаджені кавою). Вони відновили два унікальні реліктові сорти: Gori Gesha (який повторює генетику дикого лісу) та Gesha 1931 (який морфологічно ідентичний знаменитій панамській Гейші). Gesha Village розбита на 8 ''блоків'' (Gaylee, Surma, Oma тощо), кожен з яких має унікальний мікроклімат і дає різний смак. Вони працюють у повній симбіозі з лісом: зберегли старі дерева для створення 40% затінення і наймають місцеве плем''я Меаніт для збору врожаю, платячи їм у рази вище за ринкові стандарти.', 'Збереження диких ефіопських сортів (Gesha 1931, Gori Gesha), Африканські ліжка, Екологічний мікро-мілінг', 'Ethiopia');
INSERT INTO public.localized_farmer_translations (farmer_id, language_code, name, region, description, story, country) VALUES (6, 'uk', 'Адам Овертон та Рейчел Семюел', 'Бенчі-Маджі (Bench Maji), округ Менгеші (Mengeshi)', 'Історія Gesha Village — це справжній пригодницький роман у світі кави. Адам (американець, режисер-документаліст) та Рейчел (ефіопка, фотограф) приїхали до Ефіопії знімати кіно про каву, але закохалися в країну і вирішили створити власну ферму. Їхня мета була амбітною: повернути славу сорту Гейша на його історичну батьківщину. Сорт Гейша (Gesha) став світовим феноменом у Панамі, але його коріння походить з джунглів Ефіопії. У 2011 році, заручившись підтримкою ботаніків, Адам і Рейчел вирушили в експедицію до диких, незвіданих лісів Горі Геша. Вони зібрали там насіння дикорослих кавових дерев і посадили їх на своїй новій фермі площею 471 гектар (з яких 320 га засаджені кавою). Вони відновили два унікальні реліктові сорти: Gori Gesha (який повторює генетику дикого лісу) та Gesha 1931 (який морфологічно ідентичний знаменитій панамській Гейші). Gesha Village розбита на 8 ''блоків'' (Gaylee, Surma, Oma тощо), кожен з яких має унікальний мікроклімат і дає різний смак. Вони працюють у повній симбіозі з лісом: зберегли старі дерева для створення 40% затінення і наймають місцеве плем''я Меаніт для збору врожаю, платячи їм у рази вище за ринкові стандарти.', 'Збереження диких ефіопських сортів (Gesha 1931, Gori Gesha), Африканські ліжка, Екологічний мікро-мілінг', 'Ефіопія');
INSERT INTO public.localized_farmers (id, image_url, country_emoji) VALUES (7, 'https://lylnnqojnytndybhuicr.supabase.co/storage/v1/object/public/Farmers/farmer_aida_batlle_1775463622660.png', 'https://lylnnqojnytndybhuicr.supabase.co/storage/v1/object/public/Flags/coffee_country_flags_1775678067772.png');
INSERT INTO public.localized_farmer_translations (farmer_id, language_code, name, region, description, story, country) VALUES (7, 'en', 'Aida Batlle', 'Санта-Ана (Santa Ana), схили вулкана Іламатепек', 'Аїда Батлл — фермерка у п''ятому поколінні, яку журнал TIME назвав однією з найвпливовіших фігур у кавовому світі. Під час громадянської війни в Сальвадорі її родина була змушена втекти до США, але у 2002 році Аїда повернулася, щоб відродити занедбані сімейні ферми. Її підхід був революційним для регіону: вона відмовилася від масового збору врожаю і запровадила мікро-лоти, сортуючи каву за конкретними днями збору та ділянками. У 2003 році вона стала першою жінкою, яка виграла престижний конкурс Cup of Excellence. Аїда відома своїм еклектичним підходом до агрономії. Вона імпортувала насіння кенійських сортів (SL28) і висадила їх у вулканічний ґрунт Сальвадору, створивши унікальний гібридний теруар. Крім того, вона стала світовим піонером комерційного виробництва ''каскари'' — висушеної м''якоті кавової ягоди, з якої заварюють фруктовий чай. Раніше фермери просто викидали м''якоть або робили з неї добриво, а Аїда перетворила її на самостійний преміальний продукт.', 'Мита обробка в кенійському стилі (Double Fermentation), Виробництво преміальної каскари', 'El Salvador');
INSERT INTO public.localized_farmer_translations (farmer_id, language_code, name, region, description, story, country) VALUES (7, 'uk', 'Аїда Батлл', 'Санта-Ана (Santa Ana), схили вулкана Іламатепек', 'Аїда Батлл — фермерка у п''ятому поколінні, яку журнал TIME назвав однією з найвпливовіших фігур у кавовому світі. Під час громадянської війни в Сальвадорі її родина була змушена втекти до США, але у 2002 році Аїда повернулася, щоб відродити занедбані сімейні ферми. Її підхід був революційним для регіону: вона відмовилася від масового збору врожаю і запровадила мікро-лоти, сортуючи каву за конкретними днями збору та ділянками. У 2003 році вона стала першою жінкою, яка виграла престижний конкурс Cup of Excellence. Аїда відома своїм еклектичним підходом до агрономії. Вона імпортувала насіння кенійських сортів (SL28) і висадила їх у вулканічний ґрунт Сальвадору, створивши унікальний гібридний теруар. Крім того, вона стала світовим піонером комерційного виробництва ''каскари'' — висушеної м''якоті кавової ягоди, з якої заварюють фруктовий чай. Раніше фермери просто викидали м''якоть або робили з неї добриво, а Аїда перетворила її на самостійний преміальний продукт.', 'Мита обробка в кенійському стилі (Double Fermentation), Виробництво преміальної каскари', 'Сальвадор');
INSERT INTO public.specialty_articles (id, title_en, title_uk, image_url, read_time_min) VALUES (101, 'Standards, Institutions, and Ethics', 'Standards, Institutions, and Ethics', 'https://lylnnqojnytndybhuicr.supabase.co/storage/v1/object/public/specialty-articles/encyclopedia_module_1_standards_1775401113100.png', 10);
INSERT INTO public.specialty_article_translations (article_id, language_code, title, subtitle, content_html) VALUES (101, 'uk', 'Standards, Institutions, and Ethics', '', '<div style="color: #E0E0E0; font-family: -apple-system, BlinkMacSystemFont, Segoe UI, Roboto, Helvetica, Arial, sans-serif; font-size: 16px; line-height: 1.6;"><h1 style="color: #C8A96E; font-size: 32px; font-weight: 800; margin-bottom: 32px; border-bottom: 2px solid #C8A96E; padding-bottom: 12px; letter-spacing: -0.5px;">Standards, Institutions, and Ethics</h1><h2 style="color: #C8A96E; font-size: 24px; font-weight: 700; margin-top: 48px; margin-bottom: 20px; display: flex; align-items: center;"><span style="background: #C8A96E; width: 8px; height: 24px; margin-right: 12px; border-radius: 2px;"></span>Розширене визначення Specialty Coffee</h2><p style="margin-bottom: 16px; line-height: 1.6;">Specialty Coffee — це не просто категорія товару, а замкнута екосистема контролю якості, де кожен етап виробництва спрямований на збереження та підкреслення природного генетичного потенціалу зерна.</p><h3 style="color: #C8A96E; font-size: 16px; margin-top: 20px; margin-bottom: 10px;">Fundamental attributes</h3><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Attribute</h4><p style="margin-bottom: 16px;">Повна простежуваність (Traceability)</p><p style="margin-bottom: 16px; line-height: 1.6;">Можливість ідентифікувати каву до рівня конкретного лота (Micro-lot) або навіть ділянки ферми (Nano-lot). Це включає GPS-координати плантації, дату збору та точні параметри обробки.</p><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Attribute</h4><p style="margin-bottom: 16px;">Сенсорна перевага</p><p style="margin-bottom: 16px; line-height: 1.6;">Наявність унікальних смакових дескрипторів, зумовлених теруаром, а не процесом обсмажування. Кава повинна демонструвати складну кислотність, виражену солодкість та чистий післясмак.</p><hr style="border: 0; border-top: 1px solid #2A2A2A; margin: 40px 0;"><h2 style="color: #C8A96E; font-size: 24px; font-weight: 700; margin-top: 48px; margin-bottom: 20px; display: flex; align-items: center;"><span style="background: #C8A96E; width: 8px; height: 24px; margin-right: 12px; border-radius: 2px;"></span>Світові інституції: SCA та CQI</h2><h3 style="color: #C8A96E; font-size: 16px; margin-top: 20px; margin-bottom: 10px;">Organizations</h3><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Name</h4><p style="margin-bottom: 16px;">Specialty Coffee Association (SCA)</p><p style="margin-bottom: 16px; line-height: 1.6;">Глобальна неприбуткова організація, що встановлює технічні стандарти для всієї індустрії.</p><ul style="margin-bottom: 20px; padding-left: 20px;"><li style="margin-bottom: 8px; list-style-type: none; position: relative; padding-left: 20px;"><span style="color: #C8A96E; position: absolute; left: 0;">•</span> SCA Water Standard: Специфікація хімічного складу води для заварювання (TDS, кальцієва жорсткість, лужність).</li><li style="margin-bottom: 8px; list-style-type: none; position: relative; padding-left: 20px;"><span style="color: #C8A96E; position: absolute; left: 0;">•</span> SCA Cupping Protocol: Суворий регламент проведення професійних дегустацій.</li><li style="margin-bottom: 8px; list-style-type: none; position: relative; padding-left: 20px;"><span style="color: #C8A96E; position: absolute; left: 0;">•</span> SCA Green Coffee Grading: Методологія фізичного аналізу зеленого зерна перед обсмажуванням.</li></ul><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Name</h4><p style="margin-bottom: 16px;">Coffee Quality Institute (CQI)</p><p style="margin-bottom: 16px; line-height: 1.6;">Організація, що фокусується на навчанні та сертифікації спеціалістів.</p><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Certification system</h4><h5 style="color: #C8A96E; font-size: 14px; margin-top: 20px; margin-bottom: 10px;">Program name</h5><p style="margin-bottom: 16px;">Q-Grader</p><p style="margin-bottom: 16px; line-height: 1.6;">Найвищий рівень професійної сертифікації дегустатора кави. Q-грейдери — це ''судді'', які мають право офіційно виставляти бали каві, що впливає на її ринкову вартість.</p><h5 style="color: #C8A96E; font-size: 14px; margin-top: 20px; margin-bottom: 10px;">Exam structure</h5><p style="margin-bottom: 16px;">Включає 22 тести: від калібрування сенсорних навичок до ідентифікації органічних кислот та розпізнавання дефектів обсмажування.</p><hr style="border: 0; border-top: 1px solid #2A2A2A; margin: 40px 0;"><h2 style="color: #C8A96E; font-size: 24px; font-weight: 700; margin-top: 48px; margin-bottom: 20px; display: flex; align-items: center;"><span style="background: #C8A96E; width: 8px; height: 24px; margin-right: 12px; border-radius: 2px;"></span>Протокол оцінювання та Капінг</h2><h3 style="color: #C8A96E; font-size: 16px; margin-top: 20px; margin-bottom: 10px;">Cupping parameters</h3><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Standard ratio</h4><p style="margin-bottom: 16px;">8.25 грама кави на 150 мл води.</p><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Water temperature</h4><p style="margin-bottom: 16px;">92.2 – 94.4°C.</p><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Grind size</h4><p style="margin-bottom: 16px;">Крупний помел (70% часток проходять через сито 20 меш).</p><ul style="margin-bottom: 20px; padding-left: 20px;"><li style="margin-bottom: 8px; list-style-type: none; position: relative; padding-left: 20px;"><span style="color: #C8A96E; position: absolute; left: 0;">•</span> Fragrance/Aroma: Оцінка сухого та вологого аромату (після ламання ''кірки'').</li><li style="margin-bottom: 8px; list-style-type: none; position: relative; padding-left: 20px;"><span style="color: #C8A96E; position: absolute; left: 0;">•</span> Flavor: Сприйняття смаку при температурі 70°C.</li><li style="margin-bottom: 8px; list-style-type: none; position: relative; padding-left: 20px;"><span style="color: #C8A96E; position: absolute; left: 0;">•</span> Acidity: Оцінка інтенсивності та характеру кислот (яблучна, лимонна, фосфорна).</li><li style="margin-bottom: 8px; list-style-type: none; position: relative; padding-left: 20px;"><span style="color: #C8A96E; position: absolute; left: 0;">•</span> Body: Тактильне відчуття щільності та в''язкості на язику.</li><li style="margin-bottom: 8px; list-style-type: none; position: relative; padding-left: 20px;"><span style="color: #C8A96E; position: absolute; left: 0;">•</span> Uniformity: Перевірка ідентичності смаку в усіх 5 чашках одного лота.</li><li style="margin-bottom: 8px; list-style-type: none; position: relative; padding-left: 20px;"><span style="color: #C8A96E; position: absolute; left: 0;">•</span> Clean Cup: Відсутність сторонніх присмаків (земляних, хімічних, пліснявих) від початку до кінця ковтка.</li></ul><h3 style="color: #C8A96E; font-size: 16px; margin-top: 20px; margin-bottom: 10px;">Scoring system</h3><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Commercial grade</h4><p style="margin-bottom: 16px;">Нижче 80 балів (використовується для мас-маркету та сублімованої кави).</p><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Specialty grade</h4><p style="margin-bottom: 16px;">80.00 – 84.99 (Дуже хороша кава).</p><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">High specialty</h4><p style="margin-bottom: 16px;">85.00 – 89.99 (Чудова кава з яскравим терруаром).</p><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Presidential award</h4><p style="margin-bottom: 16px;">90.00 – 100.00 (Виняткова кава, часто аукціонні лоти).</p><hr style="border: 0; border-top: 1px solid #2A2A2A; margin: 40px 0;"><h2 style="color: #C8A96E; font-size: 24px; font-weight: 700; margin-top: 48px; margin-bottom: 20px; display: flex; align-items: center;"><span style="background: #C8A96E; width: 8px; height: 24px; margin-right: 12px; border-radius: 2px;"></span>Етична торгівля та Економіка</h2><h3 style="color: #C8A96E; font-size: 16px; margin-top: 20px; margin-bottom: 10px;">Models</h3><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Type</h4><p style="margin-bottom: 16px;">Direct Trade (Пряма торгівля)</p><p style="margin-bottom: 16px; line-height: 1.6;">Модель, де обсмажувальник купує каву безпосередньо у фермера, минаючи біржових посередників. Це дозволяє виплачувати ціну, що на 50-300% вища за біржову вартість C-Market.</p><h4 style="color: #C8A96E; font-size: 15px; margin-top: 20px; margin-bottom: 10px;">Type</h4><p style="margin-bottom: 16px;">Fair Trade (Справедлива торгівля)</p><p style="margin-bottom: 16px; line-height: 1.6;">Сертифікація, що гарантує мінімальну ціну захисту для фермерів та інвестиції в соціальні проєкти громад (школи, лікарні).</p><h3 style="color: #C8A96E; font-size: 16px; margin-top: 20px; margin-bottom: 10px;">Sustainability</h3><p style="margin-bottom: 16px;">Вимога до зменшення використання пестицидів та збереження біорізноманіття на фермах.</p><hr style="border: 0; border-top: 1px solid #2A2A2A; margin: 40px 0;"></div>');
